import requests
import os


class Tools:
    @staticmethod
    def run(query: str, limit: int = 10, params: dict = None) -> dict:
        """
        Search CORE API for academic papers.
        Returns title, abstract, PDF URL, authors, year, etc.
        """
        api_key = os.environ.get("CORE_API_KEY")
        if not api_key:
            return {"error": "CORE_API_KEY not found"}

        url = "https://api.core.ac.uk/v3/search/works"

        headers = {"Authorization": f"Bearer {api_key}"}

        payload = {"q": query, "limit": limit, **(params or {})}

        try:
            r = requests.post(url, headers=headers, json=payload, timeout=15)
            r.raise_for_status()
            return r.json()
        except Exception as e:
            return {"error": str(e)}
